import{_ as a,c as e,o as s,a1 as o}from"./chunks/framework.TuIRSVI8.js";const u=JSON.parse('{"title":"Wayland Screenshots on Bazzite/Steam Deck","description":"","frontmatter":{},"headers":[],"relativePath":"WAYLAND_SCREENSHOTS.md","filePath":"WAYLAND_SCREENSHOTS.md","lastUpdated":1765863345000}'),i={name:"WAYLAND_SCREENSHOTS.md"};function r(n,t,l,d,h,p){return s(),e("div",null,[...t[0]||(t[0]=[o(`<h1 id="wayland-screenshots-on-bazzite-steam-deck" tabindex="-1">Wayland Screenshots on Bazzite/Steam Deck <a class="header-anchor" href="#wayland-screenshots-on-bazzite-steam-deck" aria-label="Permalink to &quot;Wayland Screenshots on Bazzite/Steam Deck&quot;">​</a></h1><h2 id="the-problem" tabindex="-1">The Problem <a class="header-anchor" href="#the-problem" aria-label="Permalink to &quot;The Problem&quot;">​</a></h2><p>Wayland&#39;s security model prevents applications from capturing the screen directly. Unlike X11 where any app could grab pixels, Wayland requires apps to request permission through <strong>xdg-desktop-portal</strong>.</p><p>This means:</p><ul><li>Traditional screenshot tools (Flameshot, Shutter) have issues</li><li>GNOME 41+ blocks direct DBus screenshot access</li><li>Every screenshot request may show a permission dialog</li></ul><h2 id="recommended-workflow-grim-slurp-satty" tabindex="-1">Recommended Workflow: grim + slurp + Satty <a class="header-anchor" href="#recommended-workflow-grim-slurp-satty" aria-label="Permalink to &quot;Recommended Workflow: grim + slurp + Satty&quot;">​</a></h2><p>This is the native Wayland approach that works reliably:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Take screenshot with area selection, open in Satty for annotation</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">grim</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -g</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">slurp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">)&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> -</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> satty</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --filename</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> -</span></span></code></pre></div><h3 id="what-each-tool-does" tabindex="-1">What Each Tool Does <a class="header-anchor" href="#what-each-tool-does" aria-label="Permalink to &quot;What Each Tool Does&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Tool</th><th>Purpose</th><th>Install</th></tr></thead><tbody><tr><td><strong>grim</strong></td><td>Captures screenshots on Wayland</td><td><code>rpm-ostree install grim</code></td></tr><tr><td><strong>slurp</strong></td><td>Area selection overlay</td><td><code>rpm-ostree install slurp</code></td></tr><tr><td><strong>Satty</strong></td><td>Modern annotation editor (GTK4)</td><td>Bootstrap installs to <code>~/.local/bin/</code></td></tr></tbody></table><h3 id="setting-up-a-keyboard-shortcut" tabindex="-1">Setting Up a Keyboard Shortcut <a class="header-anchor" href="#setting-up-a-keyboard-shortcut" aria-label="Permalink to &quot;Setting Up a Keyboard Shortcut&quot;">​</a></h3><p>GNOME Settings → Keyboard → Custom Shortcuts:</p><ul><li><strong>Name</strong>: Screenshot + Annotate</li><li><strong>Command</strong>: <code>sh -c &#39;grim -g &quot;$(slurp)&quot; - | satty --filename -&#39;</code></li><li><strong>Key</strong>: <code>Super+Shift+S</code> (or your preference)</li></ul><h2 id="alternative-gnome-built-in" tabindex="-1">Alternative: GNOME Built-in <a class="header-anchor" href="#alternative-gnome-built-in" aria-label="Permalink to &quot;Alternative: GNOME Built-in&quot;">​</a></h2><p>Press <code>Print Screen</code> to use GNOME&#39;s native screenshot tool:</p><table tabindex="0"><thead><tr><th>Key</th><th>Action</th></tr></thead><tbody><tr><td><code>Print Screen</code></td><td>Opens screenshot UI (area/window/screen)</td></tr><tr><td><code>Shift+Print</code></td><td>Captures full screen immediately</td></tr><tr><td><code>Alt+Print</code></td><td>Captures current window</td></tr></tbody></table><p>Screenshots save to <code>~/Pictures/Screenshots/</code></p><h2 id="flameshot-on-wayland" tabindex="-1">Flameshot on Wayland <a class="header-anchor" href="#flameshot-on-wayland" aria-label="Permalink to &quot;Flameshot on Wayland&quot;">​</a></h2><p>Flameshot can work but requires portal permissions. The bootstrap script configures these automatically:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> flatpak</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> override</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --talk-name=org.freedesktop.portal.Screenshot</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> org.flameshot.Flameshot</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> flatpak</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> override</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --talk-name=org.freedesktop.portal.Desktop</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> org.flameshot.Flameshot</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> flatpak</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> override</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --talk-name=org.gnome.Shell.Screenshot</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> org.flameshot.Flameshot</span></span></code></pre></div><p><strong>Note</strong>: Even with these permissions, Flameshot may have issues on GNOME Wayland. The grim+slurp+Satty workflow is more reliable.</p><h2 id="tool-comparison" tabindex="-1">Tool Comparison <a class="header-anchor" href="#tool-comparison" aria-label="Permalink to &quot;Tool Comparison&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Tool</th><th>Wayland Support</th><th>Annotation</th><th>Notes</th></tr></thead><tbody><tr><td><strong>grim+slurp+Satty</strong></td><td>Native</td><td>Yes (Satty)</td><td>Best for Wayland</td></tr><tr><td><strong>GNOME Screenshot</strong></td><td>Native</td><td>No</td><td>Built-in, always works</td></tr><tr><td><strong>Ksnip</strong></td><td>Portal</td><td>Yes</td><td>Shows dialog each time</td></tr><tr><td><strong>Flameshot</strong></td><td>Partial</td><td>Yes</td><td>Buggy on GNOME Wayland</td></tr><tr><td><strong>Gradia</strong></td><td>N/A</td><td>Beautify</td><td>For adding backgrounds/shadows</td></tr></tbody></table><h2 id="satty-features" tabindex="-1">Satty Features <a class="header-anchor" href="#satty-features" aria-label="Permalink to &quot;Satty Features&quot;">​</a></h2><ul><li>Hardware-accelerated (OpenGL)</li><li>Brush, lines, arrows, shapes</li><li>Text annotations</li><li>Blur/pixelate sensitive info</li><li>Crop after capture</li><li>Copy to clipboard or save to file</li></ul><p>Configuration: <code>~/.config/satty/config.toml</code></p><h2 id="steam-deck-game-mode" tabindex="-1">Steam Deck Game Mode <a class="header-anchor" href="#steam-deck-game-mode" aria-label="Permalink to &quot;Steam Deck Game Mode&quot;">​</a></h2><p>In Game Mode, use the Steam overlay: <code>Steam button + R1</code> to capture screenshots. These are managed by Steam and saved to your Steam screenshots folder.</p><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><h3 id="unable-to-capture-screen" tabindex="-1">&quot;Unable to capture screen&quot; <a class="header-anchor" href="#unable-to-capture-screen" aria-label="Permalink to &quot;&quot;Unable to capture screen&quot;&quot;">​</a></h3><ul><li>Ensure grim/slurp are installed via rpm-ostree (not in distrobox)</li><li>These tools need system-level Wayland access</li></ul><h3 id="flameshot-not-working" tabindex="-1">Flameshot not working <a class="header-anchor" href="#flameshot-not-working" aria-label="Permalink to &quot;Flameshot not working&quot;">​</a></h3><ul><li>Check Flatseal for portal permissions</li><li>Try the grim+slurp+Satty workflow instead</li></ul><h3 id="satty-not-found" tabindex="-1">Satty not found <a class="header-anchor" href="#satty-not-found" aria-label="Permalink to &quot;Satty not found&quot;">​</a></h3><ul><li>Run <code>./scripts/bazzite-bootstrap.sh flatpaks</code> to install</li><li>Or manually: download from <a href="https://github.com/Satty-org/Satty/releases" target="_blank" rel="noreferrer">https://github.com/Satty-org/Satty/releases</a></li></ul><hr><p><em>Last updated: December 2025</em></p>`,37)])])}const k=a(i,[["render",r]]);export{u as __pageData,k as default};
